import React from "react";
import {
  BrowserRouter as Router,
  Routes,
  Route,
  Link,
  useLocation,
} from "react-router-dom";
import Navbar from "./Navbar";
import { motion, AnimatePresence } from "framer-motion";

// -------------------- Pages --------------------
function Home() {
  return (
    <motion.div
      className="min-h-screen flex flex-col items-center justify-center bg-gradient-to-br from-blue-100 to-purple-200 dark:from-gray-900 dark:to-gray-800"
      initial={{ opacity: 0, y: 40 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6 }}
    >
      <motion.h1
        className="text-4xl font-bold text-primary dark:text-accent mb-4"
        initial={{ scale: 0.8 }}
        animate={{ scale: 1 }}
        transition={{ duration: 0.5 }}
      >
        Welcome to Godemars Empire
      </motion.h1>
      <motion.p
        className="text-lg text-gray-700 dark:text-gray-300 text-center"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.3, duration: 0.5 }}
      >
        Explore technology, innovation, and creativity!
      </motion.p>
      <Link to="/about">
        <motion.button
          className="mt-8 px-6 py-2 bg-accent text-white rounded shadow hover:bg-primary transition"
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
        >
          Get Started
        </motion.button>
      </Link>
    </motion.div>
  );
}

function About() {
  return (
    <motion.div
      className="min-h-screen flex flex-col items-center justify-center bg-white dark:bg-gray-900"
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.5 }}
    >
      <h2 className="text-3xl font-bold text-primary dark:text-accent mb-4">
        About Us
      </h2>
      <p className="text-lg text-gray-700 dark:text-gray-300 max-w-xl text-center">
        Godemars Empire is dedicated to advancing technology and innovation.
        Join us to build the future!
      </p>
      <Link to="/">
        <button className="mt-8 px-6 py-2 bg-accent text-white rounded shadow hover:bg-primary transition">
          Back Home
        </button>
      </Link>
    </motion.div>
  );
}

// -------------------- Routes with Animation --------------------
function AnimatedRoutes() {
  const location = useLocation();
  return (
    <AnimatePresence mode="wait">
      <Routes location={location} key={location.pathname}>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
      </Routes>
    </AnimatePresence>
  );
}

// -------------------- App --------------------
function App() {
  return (
    <Router>
      <Navbar />
      <AnimatedRoutes />
    </Router>
  );
}

export default App;
